task.description:
Implement MambaBlock. depth=1 (one BidirMamba + one Mlp pair per block).
The 8 bottleneck blocks each have depth=1; parameter inflation risk addressed.

class MambaBlock(nn.Module):
  def __init__(self, dim, depth=1, d_state=16, d_conv=4, expand=2):
    self.layers = nn.ModuleList([
      BidirectionalMambaLayer(dim, d_state, d_conv, expand)
      for _ in range(depth)
    ])
    self.mlp_norms = nn.ModuleList([nn.LayerNorm(dim) for _ in range(depth)])
    self.mlps      = nn.ModuleList([MlpChannel(dim) for _ in range(depth)])

  def forward(self, x):  # x: (B,C,H,W,D)
    for bidir, ln, mlp in zip(self.layers, self.mlp_norms, self.mlps):
      x = bidir(x)                              # LN inside BidirMamba
      # MlpChannel needs (B,C,H,W,D); LN needs last dim = C
      B,C,*sp = x.shape; L = math.prod(sp)
      x_seq = x.reshape(B,C,L).permute(0,2,1)  # (B,L,C)
      x = x + mlp(ln(x_seq).permute(0,2,1).reshape(B,C,*sp))
    return x

