task.description:
Implement MambaVesselNetAdapter(ModelAdapter).

REQUIRED PATTERN (WARN-1 fix — must use self.config + self.net):
  class MambaVesselNetAdapter(ModelAdapter):
    def __init__(self, config: ModelConfig):
      super().__init__()
      self.config = config          # NOT self._config — base needs self.config
      self.net = MambaVesselNetBackbone(
        in_chans=config.in_channels,
        out_chans=config.out_channels,
        **config.architecture_params,
      )  # NOT any other attribute name — base class uses self.net for
         # trainable_parameters(), load_checkpoint(), save_checkpoint()

    def forward(self, images, **kwargs):
      logits = self.net(images)
      return self._build_output(logits, "mambavesselnet")

    def get_eval_roi_size(self): return (64, 64, 64)

    def get_config(self): return self._build_config()

    def export_onnx(self, path, example_input):
      raise NotImplementedError(
        "MambaVesselNet: mamba-ssm selective scan is not ONNX-traceable. "
        "Use TorchScript or contact maintainer for ONNX custom op registry."
      )  # D10

Register in model_builder._populate_registry():
  _MODEL_REGISTRY[ModelFamily.MAMBAVESSELNET] = _build_mambavesselnet

Add _require_mamba(config) gate:
  if not _mamba_available(): raise RuntimeError("mamba-ssm not installed...")

